
import { defineComponent } from 'vue';
import { BackupRestoreType, PaginationType } from '@/types';

export default defineComponent({
  data() {
    return {
      // loading data
      isLoading: false,
      // restores
      restores: [] as BackupRestoreType[],
      // Pagination
      pagination: {
        page: 1,
        itemsCount: 0,
        maxRecordsPerPage: 0,
        pagesCount: 0,
      } as PaginationType,
    };
  },

  mounted() {
    this.init();
  },

  methods: {
    // Init
    async init() {
      await this.getRestoresList();
    },

    // Get restores list
    async getRestoresList() {
      if (this.isLoading) return;
      this.isLoading = true;

      try {
        let restores = await this.$api['backups'].getRestoresList({ page: this.pagination.page });
        let { items, page, itemsCount, maxRecordsPerPage, pagesCount } = restores;
        this.restores = items;
        this.pagination = {
          page,
          itemsCount,
          maxRecordsPerPage,
          pagesCount,
        };
      } catch (errors: any) {
        this.$utils.showMessageError({ message: errors.server, errors });
      } finally {
        this.isLoading = false;
      }
    },

    // Get restores for page
    async changePage(page: number) {
      this.pagination.page = page;
      await this.getRestoresList();
      window.scrollTo({
        top: 0,
        behavior: 'smooth',
      });
      this.isLoading = false;
    },
  },
});
